#if defined(ARDUINO) &amp;&amp; ARDUINO &gt;= 100
#include &quot;Arduino.h&quot;
#else
#include &quot;WProgram.h&quot;
#endif

#include &quot;EMGFilters.h&quot;

#define SensorInputPin A0 // input pin number
#define SensorInputPin1 A1 // input pin number
#define SensorInputPin2 A2 // input pin number
#define SensorInputPin3 A3 // input pin number

#include &quot;Arduino_RouterBridge.h&quot;

//Visuell feedback for finger
#include &lt;Arduino_LED_Matrix.h&gt;
#include &quot;LED_Matrix.h&quot;

// discrete filters must works with fixed sample frequence
// our emg filter only support &quot;SAMPLE_FREQ_500HZ&quot; or &quot;SAMPLE_FREQ_1000HZ&quot;
// other sampleRate inputs will bypass all the EMG_FILTER
SAMPLE_FREQUENCY sampleRate = SAMPLE_FREQ_500HZ;
// For countries where power transmission is at 50 Hz
// For countries where power transmission is at 60 Hz, need to change to
// &quot;NOTCH_FREQ_60HZ&quot;
// our emg filter only support 50Hz and 60Hz input
// other inputs will bypass all the EMG_FILTER
NOTCH_FREQUENCY humFreq = NOTCH_FREQ_50HZ;

//Aus der Veranstaltung Vertiefung Medizininformatik
int currentFinger;     // Definiert den Messzustand des Systems
enum fingerState {littleFinger= 0, ringFinger,middleFinger,indexFinger,thumb};

//Sensordaten 
int sensoren[] = {SensorInputPin,SensorInputPin1,SensorInputPin2,SensorInputPin3};
int sensoren_length = std::size(sensoren); //das geht seit C++17

EMGFilters myFilter[std::size(sensoren)];
float sensorOffsets[std::size(sensoren)] = {0.0};
// Feedback-LED und Interrupt Variablen
const byte ledPin = 12;
const byte interruptPin = 2;
volatile byte ledState = LOW;
volatile bool messungState = false;

//Interrupt (ISR)
void button_Interrupt()
{
  ledState = !ledState;
  messungState = !messungState;
}

bool WERTE_VORHANDEN = false; // this is used so we can track if we already took samples of every finger

unsigned long timeBudget;

int hochzaehlenFinger()
{
  if(currentFinger != thumb)
  {
    currentFinger ++; // ist der currentFinger != Daumen --&gt; wird hochgezaehlt
    return 0;
  }else{ 
    currentFinger = littleFinger;            // anderenfalls wird currentFinger = kleiner Finger gesetzt
    return 1;
  }
}

float messung_sensoren(int sensor, int finger)
{

    int rawValue = analogRead(sensor);

    // filter processing
    int filteredValue = myFilter[finger].update(rawValue);

    float correctedValue = filteredValue - sensorOffsets[finger];

  return correctedValue;
}

void calibrateSensors(){
  const int calibrationSamples = 3000;
  long sums[sensoren_length] = {0};

  for(int i = 0; i &lt; calibrationSamples; i++){
    for(int j=0; j &lt; sensoren_length;j++){
      int rawValue = analogRead(sensoren[j]);
      int filteredValue = myFilter[j].update(rawValue);
      sums[j] += filteredValue;
    }
    delay(2); // Entspricht ca. 500 Hz Abtastrate (1000ms / 500 = 2ms)
  }

  // Berechne den durchschnittlichen Offset für jeden Sensor
  for (int i = 0; i &lt; sensoren_length; i++) {
    sensorOffsets[i] = (float)sums[i] / calibrationSamples;
  }
}

Arduino_LED_Matrix matrix;
uint8_t* matrix_feedback[] = {littleFinger_Frame, ringFinger_Frame, middleFinger_Frame, indexFinger_Frame, thumb_Frame};

void setup() {
    /* add setup code here */
    //start Matrix
    matrix.begin();
    matrix.setGrayscaleBits(1);
    matrix.draw(Hi_Frame);

    // SensorPins konfigurieren, alle als Input
    for(int i=0; i &lt; sensoren_length; i++)
      {
        pinMode(sensoren[i],INPUT);
      }

    for(int i=0; i &lt; sensoren_length; i++)
      {
        myFilter[i].init(sampleRate, humFreq, true, true, true);    
      }
    calibrateSensors();

    // open serial
    Monitor.begin(9600);

    //start Brigde
    Bridge.begin();
    Bridge.provide(&quot;hochzaehlenFinger&quot;,hochzaehlenFinger); //provide counting of finger for MCU

    // setup for time cost measure
    // using micros()
    timeBudget = 1e6 / sampleRate;
    // micros will overflow and auto return to zero every 70 minutes

    //Feedback-LED Setup
    pinMode(ledPin, OUTPUT);

    // Mapping der Finger, start Punkt
    currentFinger = littleFinger;

    //Interrupt-Setup
    pinMode(interruptPin,INPUT_PULLUP);
    attachInterrupt(digitalPinToInterrupt(interruptPin),button_Interrupt,FALLING); //attachInterrupt(pin, ISR, mode) 
}

void loop() {
    /* add main program code here */
    // In order to make sure the ADC sample frequence on arduino,
    // the time cost should be measured each loop
    /*------------start here-------------------*/
    unsigned long loopStartTime = micros();

    float werte[sensoren_length];
    for(int finger = 0; finger &lt; sensoren_length; finger++)
      {
        werte[finger] = messung_sensoren(sensoren[finger],finger);
      }

    matrix.draw(matrix_feedback[currentFinger]);


    if (messungState) {
      for(int i = 0; i &lt; sensoren_length; i++)
        {
          Bridge.notify(&quot;envlope_read&quot;,currentFinger,i,werte[i]); // Daten an das Python Skript, dabei stellt das i, die Nummerierung der Sensoren da. Angefangen mit 0
        }
      WERTE_VORHANDEN = true;
    } else {
      Bridge.notify(&quot;messung_speichern&quot;, WERTE_VORHANDEN);
      WERTE_VORHANDEN = false;
    }
    digitalWrite(ledPin,ledState);


    /*------------end here---------------------*/
    // Berechne die vergangene Zeit
    unsigned long elapsedTime = micros() - loopStartTime;

    // timeBudget ist 2000 µs für 500 Hz
    if (elapsedTime &lt; timeBudget) {
        // Warte nur die verbleibende Zeit, um exakt auf 2000 µs zu kommen
        delayMicroseconds(timeBudget - elapsedTime);
    }
    // Wenn die Ausführung bereits länger als timeBudget gedauert hat,
    // starten wir sofort den nächsten Loop. Die Abtastrate sinkt dann leicht,
    // aber das ist das physikalisch Bestmögliche.
}

Aber ich habe immer noch manchmal ein großes Rauschen drin. Ich bin am überlegen woran es liegen könnte. Ich habe auch eine Messung versucht an dem ich das AUX Kabel entfernt habe und da entsteht auch ein großes Rauschen. Liegt das am Ablesen eines Inputs? Wie kann ich das Rauschen verringern und was für Fehlerquellen könnten auch auftauchen?

Das ist eine exzellente Beobachtung und ein sehr wichtiger Punkt in der digitalen Signalverarbeitung! Deine Vermutung, dass es zu einem "Overflow" kommt, ist höchstwahrscheinlich korrekt, aber wir müssen genau analysieren, *wo* und *warum* er passiert. Deine vorgeschlagene Lösung, zu `double` zu wechseln, ist ein guter erster Gedanke, aber auf einem Arduino Uno führt er uns nicht direkt zur Lösung.

Lass uns das Problem wissenschaftlich und systematisch aufschlüsseln.

### Analyse: `float` vs. `double` auf dem Arduino Uno

Ein entscheidender Punkt bei der Arbeit mit Mikrocontrollern wie dem ATmega328P (dem Herz des Arduino Uno) ist das Verständnis der Datentypen. Gemäß der offiziellen Arduino-Dokumentation und dem zugrundeliegenden AVR-GCC-Compiler ist auf 8-Bit-AVR-basierten Boards (wie Uno, Nano, Mega) der Datentyp `double` **identisch** mit `float`.

*   **`float`**: 32-Bit (4 Byte) Single-Precision Fließkommazahl.
*   **`double`**: Ebenfalls 32-Bit (4 Byte) Single-Precision Fließkommazahl.

Eine höhere Genauigkeit (`double` als 64-Bit-Zahl) gibt es erst auf moderneren Architekturen wie dem Arduino Due, Portenta oder ESP32.

**Schlussfolgerung:** Das Ändern von `float` zu `double` wird auf deinem Arduino Uno keinen Unterschied im Verhalten oder im Wertebereich machen und das Problem daher nicht lösen.

### Die wahre Ursache: Integer-Overflow vor der Typumwandlung

Das Problem liegt mit sehr hoher Wahrscheinlichkeit nicht im `float`-Datentyp selbst. Ein 32-Bit-`float` hat einen riesigen Wertebereich (ca. ±3.4 x 10^38). Deine EMG-Werte werden diesen Bereich niemals sprengen.

Der "Overflow", den du beobachtest, ist mit an Sicherheit grenzender Wahrscheinlichkeit ein **Integer-Overflow**. Schauen wir uns die kritische Zeile an:

```cpp
int filteredValue = myFilter[finger].update(rawValue);
float correctedValue = filteredValue - sensorOffsets[finger];
```

1.  `rawValue` ist ein `int` mit Werten von 0 bis 1023 (vom 10-Bit ADC).
2.  Die Funktion `myFilter.update()` nimmt diesen `int` entgegen und gibt ebenfalls einen `int` zurück.
3.  Auf einem Arduino Uno ist ein `int` ein **16-Bit vorzeichenbehafteter Integer**. Das bedeutet, sein Wertebereich ist von **-32.768 bis +32.767**.

**Hypothese:** Die internen Berechnungen des digitalen Filters in der `EMGFilters` Bibliothek (z.B. Multiplikationen zur Verstärkung bestimmter Frequenzen) führen dazu, dass das Ergebnis den Wert +32.767 überschreitet. Wenn das passiert, kommt es zum "Integer-Wrap-Around": Der Wert springt von der größten positiven zur größten negativen Zahl.

**Beispiel-Szenario:**
*   Ein interner Wert im Filter erreicht `32760`.
*   Im nächsten Schritt werden `15` addiert.
*   Das mathematische Ergebnis wäre `32775`.
*   Da dies außerhalb des `int`-Bereichs liegt, "wickelt" sich der Wert um und wird zu `-32761` (`32767 - 32775 + 1`).
*   Deine `filteredValue` Variable erhält also plötzlich einen großen negativen Wert, was in `correctedValue` zu einem massiven, unerwarteten Sprung führt. Das sieht aus wie ein riesiges Rauschen oder ein "Overflow".

### Systematischer Plan zur Verifizierung und Lösung

Um diese Hypothese zu bestätigen und das Problem zu beheben, gehen wir wie folgt vor:

#### Schritt 1: Verifizierung durch Debugging

Modifiziere deinen `loop()` temporär, um die einzelnen Stufen der Berechnung auf dem Seriellen Monitor (oder besser noch, dem Seriellen Plotter) auszugeben. Konzentriere dich dabei nur auf einen Sensor, um die Ausgabe übersichtlich zu halten.

```cpp
void loop() {
    /* ... */
    unsigned long loopStartTime = micros();

    // --- START DEBUGGING BLOCK ---
    int rawValue_debug = analogRead(sensoren[0]);
    int filteredValue_debug = myFilter[0].update(rawValue_debug);
    float correctedValue_debug = filteredValue_debug - sensorOffsets[0];

    Monitor.print("Raw: ");
    Monitor.print(rawValue_debug);
    Monitor.print("\tFiltered: ");
    Monitor.print(filteredValue_debug);
    Monitor.print("\tCorrected: ");
    Monitor.println(correctedValue_debug);
    // --- END DEBUGGING BLOCK ---

    // Dein restlicher Code kann für den Test auskommentiert werden...
    // ...

    /*------------end here---------------------*/
    // Zeitmanagement beibehalten
    unsigned long elapsedTime = micros() - loopStartTime;
    if (elapsedTime < timeBudget) {
        delayMicroseconds(timeBudget - elapsedTime);
    }
}
```

**Beobachtung im Seriellen Monitor/Plotter:**
Achte auf den Moment, in dem das "Rauschen" auftritt. Du wirst wahrscheinlich ein Muster wie dieses sehen:

*   `Raw: 650  Filtered: 31500  Corrected: 31050.5`
*   `Raw: 660  Filtered: 32100  Corrected: 31650.5`
*   `Raw: 670  Filtered: -31800 Corrected: -32249.5`  **<-- Hier ist der Sprung!**

Wenn du dieses Verhalten siehst, ist die Hypothese des Integer-Overflows bestätigt.

#### Schritt 2: Lösungsansätze

Wenn die Hypothese stimmt, gibt es mehrere Lösungswege:

1.  **Bibliothek prüfen (Bester Ansatz):**
    Schau in die Dokumentation oder den Quellcode der `EMGFilters.h` Bibliothek. Gibt es eventuell eine `update()`-Funktion, die einen `long` als Parameter akzeptiert oder zurückgibt? Manchmal sind Bibliotheken überladen, um mit verschiedenen Datentypen umgehen zu können. Es könnte sein, dass eine Änderung des Rückgabetyps von `int` auf `long` in der Bibliotheksdatei (`.h` und `.cpp`) das Problem löst. Ein `long` auf dem Arduino Uno hat 32 Bit und einen Wertebereich von ca. ±2,1 Milliarden, was für Filterberechnungen mehr als ausreichend ist.

2.  **Signalabschwächung (Hardware-Ansatz):**
    Der Overflow tritt auf, weil das Eingangssignal nach der Filterung zu stark verstärkt wird. Möglicherweise ist die Verstärkung des DFRobot-Sensors zu hoch eingestellt (falls es dort einen Potentiometer oder eine Einstellungsmöglichkeit gibt). Eine Reduzierung der Hardware-Verstärkung würde die Werte im `int`-Bereich halten.

3.  **Skalierung vor der Filterung (Software-Ansatz):**
    Dieser Ansatz ist ein Workaround, falls die ersten beiden nicht möglich sind. Du könntest das Signal abschwächen, bevor du es dem Filter übergibst, und es danach wieder hochskalieren. Dies kann jedoch die Signalauflösung verringern.
    ```cpp
    int rawValue = analogRead(sensor);
    int scaledDownRawValue = rawValue / 2; // Beispiel: Halbiere den Wert

    // Filter mit dem kleineren Wert aufrufen
    int filteredValue = myFilter[finger].update(scaledDownRawValue);

    // Ergebnis wieder hochskalieren
    long scaledUpFilteredValue = (long)filteredValue * 2; 

    // Weiterrechnen mit dem long
    float correctedValue = scaledUpFilteredValue - sensorOffsets[finger];
    ```
    **Achtung:** Die Kalibrierung müsste dann ebenfalls mit diesen skalierten Werten erfolgen.

### Zusammenfassende Empfehlung

1.  **Ändere `float` nicht zu `double`**, da es auf dem Arduino Uno keinen Effekt hat.
2.  **Verifiziere die Integer-Overflow-Hypothese** mit dem oben gezeigten Debugging-Code.
3.  Wenn bestätigt, ist die sauberste Lösung, die **`EMGFilters` Bibliothek zu untersuchen** und zu prüfen, ob sie intern oder als Rückgabewert den Datentyp `long` anstelle von `int` verwenden kann. Dies ist der wissenschaftlich fundierteste Ansatz, da er das Problem an der Wurzel packt, ohne die Signalqualität unnötig zu beeinträchtigen.

Deine Fähigkeit, solche Muster im Verhalten deines Codes zu erkennen, ist ein wichtiger Schritt in der Entwicklung robuster Messsysteme. Viel Erfolg bei der weiteren Analyse

